import re
import os
import json

def strip_go_comments(text):
    """Strip comments and string contents from Go source (preserving newlines)."""
    result = []
    i = 0
    n = len(text)
    in_line_comment = False
    in_block_comment = False
    in_backtick = False
    in_dquote = False

    while i < n:
        c = text[i]
        if in_line_comment:
            if c == '\n':
                in_line_comment = False
                result.append('\n')
            else:
                result.append(' ')
        elif in_block_comment:
            if c == '*' and i + 1 < n and text[i+1] == '/':
                in_block_comment = False
                result.append('  ')
                i += 2
                continue
            elif c == '\n':
                result.append('\n')
            else:
                result.append(' ')
        elif in_backtick:
            if c == '`':
                in_backtick = False
            if c == '\n':
                result.append('\n')
            else:
                result.append(' ')
        elif in_dquote:
            if c == '\\' and i + 1 < n:
                result.append('  ')
                i += 2
                continue
            if c == '"':
                in_dquote = False
            result.append(' ')
        else:
            if c == '/' and i + 1 < n:
                if text[i+1] == '/':
                    in_line_comment = True
                    result.append('  ')
                    i += 2
                    continue
                elif text[i+1] == '*':
                    in_block_comment = True
                    result.append('  ')
                    i += 2
                    continue
            elif c == '`':
                in_backtick = True
                result.append(' ')
                i += 1
                continue
            elif c == '"':
                in_dquote = True
                result.append(' ')
                i += 1
                continue
            result.append(c)
        i += 1
    return ''.join(result)


def find_typemeta_structs(filepath, typemeta_check_fn):
    """Find struct names that embed TypeMeta using comment-stripped source for brace counting."""
    try:
        with open(filepath) as f:
            original = f.read()
    except:
        return []

    stripped = strip_go_comments(original)
    s_lines = stripped.split('\n')
    o_lines = original.split('\n')

    found = []
    i = 0
    while i < len(s_lines):
        line = s_lines[i]
        m = re.match(r'^\s*type\s+(\w+)\s+struct\s*\{', line)
        if m:
            struct_name = m.group(1)
            # Count braces using stripped lines (no comment braces)
            brace_count = line.count('{') - line.count('}')
            j = i + 1
            while j < len(s_lines) and brace_count > 0:
                brace_count += s_lines[j].count('{') - s_lines[j].count('}')
                j += 1
            # Check original struct body for TypeMeta embedding
            orig_body = '\n'.join(o_lines[i:j])
            if typemeta_check_fn(orig_body, struct_name):
                found.append(struct_name)
            i = j
        else:
            i += 1
    return found


def has_metav1_typemeta(body, name):
    """Check if struct body has metav1.TypeMeta embedded (api repo pattern)."""
    # Look for line like: \tmetav1.TypeMeta `...`  (embedded, no field name)
    for line in body.split('\n'):
        stripped = line.strip()
        # Embedded field: just the type, possibly with tag
        if re.match(r'^metav1\.TypeMeta(\s|`|$)', stripped):
            return True
    return False


def has_bare_typemeta(body, name):
    """Check if struct body has bare TypeMeta embedded (same-package pattern)."""
    for line in body.split('\n'):
        stripped = line.strip()
        if re.match(r'^TypeMeta(\s|`|$)', stripped):
            return True
    return False


def get_all_deepcopy_implementors(base_dir):
    implementors = set()
    for root, dirs, files in os.walk(base_dir):
        dirs[:] = [d for d in dirs if d != 'vendor']
        for fname in files:
            if not fname.endswith('.go') or fname.endswith('_test.go'):
                continue
            fpath = os.path.join(root, fname)
            try:
                with open(fpath) as f:
                    content = f.read()
                for m in re.finditer(r'func\s+\(\w+\s+\*?(\w+)\)\s+DeepCopyObject\(\)', content):
                    implementors.add(m.group(1))
            except:
                pass
    return implementors


