package main

import (
	"encoding/json"
	"fmt"
	"go/ast"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"strings"
)

type Implementor struct {
	Repo       string `json:"repo"`
	File       string `json:"file"`
	StructName string `json:"struct_name"`
}

func main() {
	var results []Implementor

	// Process kubernetes/api
	apiResults := findImplementors("/workspace/api", "kubernetes/api")
	results = append(results, apiResults...)

	// Process kubernetes/apimachinery
	apmResults := findImplementors("/workspace/apimachinery", "kubernetes/apimachinery")
	results = append(results, apmResults...)

	// Write JSON
	out, err := json.MarshalIndent(results, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile("/workspace/implementors.json", out, 0644); err != nil {
		panic(err)
	}
	fmt.Printf("Total implementors found: %d\n", len(results))
}

func findImplementors(baseDir, repoName string) []Implementor {
	// Step 1: Find all types with DeepCopyObject() method (from all .go files including generated)
	deepCopyTypes := findDeepCopyObjectTypes(baseDir)

	// Step 2: Find all structs that embed TypeMeta (metav1.TypeMeta or bare TypeMeta)
	// in non-generated, non-test types files
	typeMetaStructs := findTypeMetaStructs(baseDir)

	// Also find structs with explicit GetObjectKind() (non-embedded TypeMeta)
	explicitObjKind := findExplicitGetObjectKind(baseDir)

	var results []Implementor
	seen := map[string]bool{}

	// A type implements runtime.Object if it has both GetObjectKind (via TypeMeta or explicit) AND DeepCopyObject
	for filePath, structs := range typeMetaStructs {
		relPath, _ := filepath.Rel(baseDir, filePath)
		for _, structName := range structs {
			key := relPath + ":" + structName
			if seen[key] {
				continue
			}
			// Check DeepCopyObject exists for this struct
			if deepCopyTypes[structName] {
				// Exclusion criteria
				if shouldExclude(relPath, structName) {
					continue
				}
				seen[key] = true
				results = append(results, Implementor{
					Repo:       repoName,
					File:       relPath,
					StructName: structName,
				})
			}
		}
	}

	// Also check explicit GetObjectKind implementors
	for filePath, structs := range explicitObjKind {
		relPath, _ := filepath.Rel(baseDir, filePath)
		for _, structName := range structs {
			key := relPath + ":" + structName
			if seen[key] {
				continue
			}
			if deepCopyTypes[structName] {
				if shouldExclude(relPath, structName) {
					continue
				}
				seen[key] = true
				results = append(results, Implementor{
					Repo:       repoName,
					File:       relPath,
					StructName: structName,
				})
			}
		}
	}

	fmt.Printf("%s: found %d implementors\n", repoName, len(results))
	return results
}

func shouldExclude(relPath, structName string) bool {
	// Exclude list types
	if strings.HasSuffix(structName, "List") {
		return true
	}
	// Exclude generated files
	if strings.HasSuffix(relPath, "_generated.go") ||
		strings.Contains(relPath, "zz_generated") {
		return true
	}
	// Exclude test files
	if strings.HasSuffix(relPath, "_test.go") {
		return true
	}
	// Exclude vendor
	if strings.Contains(relPath, "/vendor/") {
		return true
	}
	// Exclude test packages
	if strings.Contains(relPath, "/testing/") ||
		strings.Contains(relPath, "testapigroup") {
		return true
	}
	// Exclude pkg/test/
	if strings.HasPrefix(relPath, "pkg/test/") {
		return true
	}
	// Exclude internal-only types
	if strings.Contains(relPath, "/internalversion/") {
		return true
	}
	return false
}

// findDeepCopyObjectTypes finds all struct names with DeepCopyObject() methods
// (includes generated files since that's where most DeepCopyObject methods live)
func findDeepCopyObjectTypes(baseDir string) map[string]bool {
	result := map[string]bool{}

	filepath.Walk(baseDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info.IsDir() {
			return nil
		}
		if !strings.HasSuffix(path, ".go") {
			return nil
		}
		if strings.Contains(path, "/vendor/") {
			return filepath.SkipDir
		}
		if strings.HasSuffix(path, "_test.go") {
			return nil
		}
		// Parse with AST
		fset := token.NewFileSet()
		f, err := parser.ParseFile(fset, path, nil, 0)
		if err != nil {
			return nil
		}
		for _, decl := range f.Decls {
			funcDecl, ok := decl.(*ast.FuncDecl)
			if !ok {
				continue
			}
			if funcDecl.Name.Name != "DeepCopyObject" {
				continue
			}
			if funcDecl.Recv == nil || len(funcDecl.Recv.List) == 0 {
				continue
			}
			// Get receiver type name
			recvType := funcDecl.Recv.List[0].Type
			if starExpr, ok := recvType.(*ast.StarExpr); ok {
				if ident, ok := starExpr.X.(*ast.Ident); ok {
					result[ident.Name] = true
				}
			} else if ident, ok := recvType.(*ast.Ident); ok {
				result[ident.Name] = true
			}
		}
		return nil
	})
	return result
}

// findTypeMetaStructs finds structs that embed TypeMeta (via metav1.TypeMeta or bare TypeMeta)
func findTypeMetaStructs(baseDir string) map[string][]string {
	result := map[string][]string{}

	filepath.Walk(baseDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info.IsDir() {
			return nil
		}
		if !strings.HasSuffix(path, ".go") {
			return nil
		}
		if strings.Contains(path, "/vendor/") {
			return filepath.SkipDir
		}
		// Only look in non-generated, non-test types files
		base := filepath.Base(path)
		if strings.HasSuffix(base, "_test.go") {
			return nil
		}
		if strings.HasPrefix(base, "zz_generated") ||
			strings.HasSuffix(base, "_generated.go") {
			return nil
		}

		fset := token.NewFileSet()
		f, err := parser.ParseFile(fset, path, nil, 0)
		if err != nil {
			return nil
		}

		for _, decl := range f.Decls {
			genDecl, ok := decl.(*ast.GenDecl)
			if !ok || genDecl.Tok != token.TYPE {
				continue
			}
			for _, spec := range genDecl.Specs {
				typeSpec, ok := spec.(*ast.TypeSpec)
				if !ok {
					continue
				}
				structType, ok := typeSpec.Type.(*ast.StructType)
				if !ok {
					continue
				}
				if hasTypeMetaEmbedded(structType) {
					result[path] = append(result[path], typeSpec.Name.Name)
				}
			}
		}
		return nil
	})
	return result
}

// findExplicitGetObjectKind finds structs that have explicit GetObjectKind() methods
func findExplicitGetObjectKind(baseDir string) map[string][]string {
	result := map[string][]string{}

	filepath.Walk(baseDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info.IsDir() {
			return nil
		}
		if !strings.HasSuffix(path, ".go") {
			return nil
		}
		if strings.Contains(path, "/vendor/") {
			return filepath.SkipDir
		}
		base := filepath.Base(path)
		if strings.HasSuffix(base, "_test.go") {
			return nil
		}
		if strings.HasPrefix(base, "zz_generated") ||
			strings.HasSuffix(base, "_generated.go") {
			return nil
		}

		fset := token.NewFileSet()
		f, err := parser.ParseFile(fset, path, nil, 0)
		if err != nil {
			return nil
		}

		for _, decl := range f.Decls {
			funcDecl, ok := decl.(*ast.FuncDecl)
			if !ok {
				continue
			}
			if funcDecl.Name.Name != "GetObjectKind" {
				continue
			}
			if funcDecl.Recv == nil || len(funcDecl.Recv.List) == 0 {
				continue
			}
			recvType := funcDecl.Recv.List[0].Type
			var typeName string
			if starExpr, ok := recvType.(*ast.StarExpr); ok {
				if ident, ok := starExpr.X.(*ast.Ident); ok {
					typeName = ident.Name
				}
			} else if ident, ok := recvType.(*ast.Ident); ok {
				typeName = ident.Name
			}
			if typeName != "" {
				result[path] = append(result[path], typeName)
			}
		}
		return nil
