func hasTypeMetaEmbedded(structType *ast.StructType) bool {
	for _, field := range structType.Fields.List {
		// Embedded fields have no names
		if len(field.Names) > 0 {
			continue
		}
		if isTypeMeta(field.Type) {
			return true
		}
	}
	return false
}

func isTypeMeta(expr ast.Expr) bool {
	switch t := expr.(type) {
	case *ast.Ident:
		return t.Name == "TypeMeta"
	case *ast.SelectorExpr:
		if ident, ok := t.X.(*ast.Ident); ok {
			return ident.Name == "metav1" && t.Sel.Name == "TypeMeta"
		}
	}
	return false
}

