import re
import os
import json

def strip_go_comments(text):
    result = []
    i = 0
    n = len(text)
    in_line_comment = False
    in_block_comment = False
    in_backtick = False
    in_dquote = False

    while i < n:
        c = text[i]
        if in_line_comment:
            if c == '\n':
                in_line_comment = False
                result.append('\n')
            else:
                result.append(' ')
        elif in_block_comment:
            if c == '*' and i + 1 < n and text[i+1] == '/':
                in_block_comment = False
                result.append('  ')
                i += 2
                continue
            elif c == '\n':
                result.append('\n')
            else:
                result.append(' ')
        elif in_backtick:
            if c == '`':
                in_backtick = False
            if c == '\n':
                result.append('\n')
            else:
                result.append(' ')
        elif in_dquote:
            if c == '\\' and i + 1 < n:
                result.append('  ')
                i += 2
                continue
            if c == '"':
                in_dquote = False
            result.append(' ')
        else:
            if c == '/' and i + 1 < n:
                if text[i+1] == '/':
                    in_line_comment = True
                    result.append('  ')
                    i += 2
                    continue
                elif text[i+1] == '*':
                    in_block_comment = True
                    result.append('  ')
                    i += 2
                    continue
            elif c == '`':
                in_backtick = True
                result.append(' ')
                i += 1
                continue
            elif c == '"':
                in_dquote = True
                result.append(' ')
                i += 1
                continue
            result.append(c)
        i += 1
    return ''.join(result)


def find_typemeta_structs(filepath, check_fn):
    try:
        with open(filepath) as f:
            original = f.read()
    except:
        return []

    stripped = strip_go_comments(original)
    s_lines = stripped.split('\n')
    o_lines = original.split('\n')

    found = []
    i = 0
    while i < len(s_lines):
        line = s_lines[i]
        m = re.match(r'^\s*type\s+(\w+)\s+struct\s*\{', line)
        if m:
            struct_name = m.group(1)
            brace_count = line.count('{') - line.count('}')
            j = i + 1
            while j < len(s_lines) and brace_count > 0:
                brace_count += s_lines[j].count('{') - s_lines[j].count('}')
                j += 1
            orig_body = '\n'.join(o_lines[i:j])
            if check_fn(orig_body):
                found.append(struct_name)
            i = j
        else:
            i += 1
    return found


def has_api_typemeta(body):
    """metav1.TypeMeta, v1.TypeMeta, or k8s_io*.TypeMeta embedded field."""
    for line in body.split('\n'):
        stripped = line.strip()
        # Embedded field: <pkg>.TypeMeta possibly with tag
        if re.match(r'^(metav1|v1|k8s_io\w*)\.TypeMeta(\s|`|$)', stripped):
            return True
    return False


def has_bare_typemeta(body):
    for line in body.split('\n'):
        stripped = line.strip()
        if re.match(r'^TypeMeta(\s|`|$)', stripped):
            return True
    return False


def get_all_deepcopy_implementors(base_dir):
    implementors = set()
    for root, dirs, files in os.walk(base_dir):
        dirs[:] = [d for d in dirs if d != 'vendor']
        for fname in files:
            if not fname.endswith('.go') or fname.endswith('_test.go'):
                continue
            fpath = os.path.join(root, fname)
            try:
                with open(fpath) as f:
                    content = f.read()
                for m in re.finditer(r'func\s+\(\w+\s+\*?(\w+)\)\s+DeepCopyObject\(\)', content):
                    implementors.add(m.group(1))
            except:
                pass
    return implementors


print("Collecting DeepCopyObject implementors...")
api_deepcopy = get_all_deepcopy_implementors('/workspace/api')
apm_deepcopy = get_all_deepcopy_implementors('/workspace/apimachinery')
print(f"  kubernetes/api: {len(api_deepcopy)} types")
print(f"  kubernetes/apimachinery: {len(apm_deepcopy)} types")

results = []

# ---- kubernetes/api ----
print("\nProcessing kubernetes/api...")
api_base = '/workspace/api'
for root, dirs, files in os.walk(api_base):
    dirs[:] = [d for d in dirs if d != 'vendor']
    for fname in sorted(files):
        if not fname.endswith('.go'):
            continue
        if fname.endswith('_test.go') or fname.startswith('zz_generated') or fname.endswith('_generated.go'):
            continue
        if not fname.endswith('types.go'):
            continue
        fpath = os.path.join(root, fname)
        structs = find_typemeta_structs(fpath, has_api_typemeta)
        for struct_name in structs:
            if struct_name.endswith('List') or struct_name == 'List':
                continue
            if struct_name not in api_deepcopy:
                continue
            rel_path = os.path.relpath(fpath, api_base)
            results.append({
                "repo": "kubernetes/api",
                "file": rel_path,
                "struct_name": struct_name
            })
print(f"  Found {len(results)} types")

# ---- kubernetes/apimachinery ----
print("\nProcessing kubernetes/apimachinery...")
apm_results = []

# meta/v1/types.go
meta_v1_types = '/workspace/apimachinery/pkg/apis/meta/v1/types.go'
structs = find_typemeta_structs(meta_v1_types, has_bare_typemeta)
for struct_name in structs:
    if struct_name.endswith('List') or struct_name == 'List' or struct_name == 'TypeMeta':
        continue
    if struct_name not in apm_deepcopy:
        continue
    apm_results.append({
        "repo": "kubernetes/apimachinery",
        "file": "pkg/apis/meta/v1/types.go",
        "struct_name": struct_name
    })

# WatchEvent in meta/v1/watch.go
with open('/workspace/apimachinery/pkg/apis/meta/v1/watch.go') as f:
    wc = f.read()
if 'type WatchEvent struct' in wc and 'WatchEvent' in apm_deepcopy:
    apm_results.append({
        "repo": "kubernetes/apimachinery",
        "file": "pkg/apis/meta/v1/watch.go",
        "struct_name": "WatchEvent"
    })

# runtime/types.go - Unknown struct
runtime_types = '/workspace/apimachinery/pkg/runtime/types.go'
structs = find_typemeta_structs(runtime_types, has_bare_typemeta)
for struct_name in structs:
    if struct_name.endswith('List') or struct_name == 'List':
        continue
    if struct_name not in apm_deepcopy:
        continue
    apm_results.append({
        "repo": "kubernetes/apimachinery",
        "file": "pkg/runtime/types.go",
        "struct_name": struct_name
    })

print(f"  Found {len(apm_results)} types")

all_results = results + apm_results
all_results.sort(key=lambda x: (x['repo'], x['file'], x['struct_name']))
print(f"\nGrand total: {len(all_results)}")

# Show by file
from collections import defaultdict
by_file = defaultdict(list)
for item in all_results:
    by_file[(item['repo'], item['file'])].append(item['struct_name'])
for key in sorted(by_file.keys()):
    print(f"  {key[1]}: {sorted(by_file[key])}")

with open('/workspace/implementors.json', 'w') as f:
    json.dump(all_results, f, indent=2)
print("\nWritten to /workspace/implementors.json")
